import { useCallback, useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import { deleteVehicle, getVehicles } from "../../api/vehicleApi";
import { getAuth } from "../../utils/auth";
import {
  FUEL_TYPES,
  TRANSMISSION_TYPES,
  VEHICLE_TYPES,
  formatCurrency,
  getVehicleStatusMeta,
} from "./VehicleInventoryForm";

const API_ORIGIN = "http://localhost:8070";

function getImageUrl(url) {
  if (!url) return "";
  return url.startsWith("http") ? url : `${API_ORIGIN}${url}`;
}

function MetricCard({ label, value, sub }) {
  return (
    <div className="kpiCard">
      <div className="kpiLabel">{label}</div>
      <div className="kpiValue" style={{ fontSize: "22px" }}>{value}</div>
      <div className="kpiSub">{sub}</div>
    </div>
  );
}

function DetailRow({ label, value }) {
  return (
    <div style={{ display: "flex", justifyContent: "space-between", gap: "12px", alignItems: "flex-start" }}>
      <div style={{ fontSize: "12px", textTransform: "uppercase", letterSpacing: "0.06em", color: "var(--text-muted)", minWidth: "92px" }}>
        {label}
      </div>
      <div style={{ textAlign: "right", color: "var(--text)", fontWeight: 600 }}>{value}</div>
    </div>
  );
}

export default function VehicleList() {
  const [vehicles, setVehicles] = useState([]);
  const [loading, setLoading] = useState(false);
  const [filters, setFilters] = useState({
    q: "",
    type: "",
    fuelType: "",
    transmission: "",
    minPrice: "",
    maxPrice: "",
    minYear: "",
    maxYear: "",
    maxMileage: "",
  });
  const navigate = useNavigate();

  const auth = getAuth();
  const role = auth?.role;
  const canManageVehicles = role === "admin" || role === "manager";

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const params = Object.fromEntries(
        Object.entries(filters).filter(([, value]) => String(value ?? "").trim() !== "")
      );
      const response = await getVehicles(params);
      setVehicles(response.data || []);
    } catch (err) {
      alert(err.response?.data?.message || "Failed to load vehicles");
    } finally {
      setLoading(false);
    }
  }, [filters]);

  useEffect(() => {
    load();
  }, [load]);

  const stats = useMemo(() => {
    const total = vehicles.length;
    const available = vehicles.filter((vehicle) => vehicle.status === "available").length;
    const reserved = vehicles.filter((vehicle) => vehicle.status === "reserved").length;
    const sold = vehicles.filter((vehicle) => vehicle.status === "sold").length;
    const totalValue = vehicles.reduce((sum, vehicle) => sum + Number(vehicle.price || 0), 0);

    return { total, available, reserved, sold, totalValue };
  }, [vehicles]);

  const activeFilterCount = useMemo(
    () => Object.values(filters).filter((value) => String(value ?? "").trim() !== "").length,
    [filters]
  );

  const onFilterChange = (event) => {
    const { name, value } = event.target;
    setFilters((current) => ({ ...current, [name]: value }));
  };

  const resetFilters = () => {
    setFilters({
      q: "",
      type: "",
      fuelType: "",
      transmission: "",
      minPrice: "",
      maxPrice: "",
      minYear: "",
      maxYear: "",
      maxMileage: "",
    });
  };

  const bookNow = (vehicleId, status) => {
    if (status !== "available") return alert("This vehicle is not available for booking.");
    if (!localStorage.getItem("token")) {
      alert("Please login to book an appointment.");
      return navigate("/login");
    }
    navigate("/book-appointment", { state: { vehicleId } });
  };

  const onDelete = async (id) => {
    if (!canManageVehicles) return alert("Access denied");
    if (!window.confirm("Delete this vehicle permanently?")) return;

    try {
      await deleteVehicle(id);
      setVehicles((current) => current.filter((vehicle) => vehicle._id !== id));
      alert("Vehicle deleted");
    } catch (err) {
      alert(err.response?.data?.message || "Delete failed");
    }
  };

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">Vehicle Inventory</div>
        </div>
      </div>

      <div className="kpiGrid">
        <MetricCard label="Total Vehicles" value={loading ? "—" : stats.total} sub="Complete inventory" />
        <MetricCard label="Available" value={loading ? "—" : stats.available} sub="Ready for appointments" />
        <MetricCard label="Reserved" value={loading ? "—" : stats.reserved} sub="Pending commitments" />
        <MetricCard label="Inventory Value" value={loading ? "—" : formatCurrency(stats.totalValue)} sub="Combined listed value" />
      </div>

      <div className="card cardPad" style={{ marginBottom: "20px", display: "grid", gap: "18px" }}>
        <div className="row" style={{ alignItems: "center", flexWrap: "wrap" }}>
          <div>
            <div className="sectionTitle">Browse Inventory</div>
            <div className="sub">Search by preference and refine inventory by price, year, fuel, transmission, and mileage.</div>
          </div>

          <div style={{ display: "flex", gap: "10px", alignItems: "center", marginLeft: "auto", flexWrap: "wrap" }}>
            <button className="btn" onClick={load} disabled={loading}>
              {loading ? "Refreshing..." : "Refresh"}
            </button>

            <button className="btn" onClick={resetFilters} disabled={loading && activeFilterCount === 0}>
              Clear Filters{activeFilterCount ? ` (${activeFilterCount})` : ""}
            </button>

            {canManageVehicles && (
              <button className="btn btnPrimary" onClick={() => navigate("/vehicles/add")}>
                Add Vehicle
              </button>
            )}
          </div>
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))", gap: "12px" }}>
          <input
            className="input"
            name="q"
            value={filters.q}
            onChange={onFilterChange}
            placeholder="Search brand, notes, reg no..."
          />

          <select className="select" name="type" value={filters.type} onChange={onFilterChange}>
            <option value="">All Types</option>
            {VEHICLE_TYPES.map((type) => (
              <option key={type} value={type}>
                {type}
              </option>
            ))}
          </select>

          <select className="select" name="fuelType" value={filters.fuelType} onChange={onFilterChange}>
            <option value="">All Fuel Types</option>
            {FUEL_TYPES.map((fuelType) => (
              <option key={fuelType} value={fuelType}>
                {fuelType}
              </option>
            ))}
          </select>

          <select className="select" name="transmission" value={filters.transmission} onChange={onFilterChange}>
            <option value="">All Transmissions</option>
            {TRANSMISSION_TYPES.map((transmission) => (
              <option key={transmission} value={transmission}>
                {transmission}
              </option>
            ))}
          </select>

          <input className="input" type="number" min="0" name="minPrice" value={filters.minPrice} onChange={onFilterChange} placeholder="Min Price" />
          <input className="input" type="number" min="0" name="maxPrice" value={filters.maxPrice} onChange={onFilterChange} placeholder="Max Price" />
          <input className="input" type="number" min="1900" name="minYear" value={filters.minYear} onChange={onFilterChange} placeholder="Min Year" />
          <input className="input" type="number" min="1900" name="maxYear" value={filters.maxYear} onChange={onFilterChange} placeholder="Max Year" />
          <input className="input" type="number" min="0" name="maxMileage" value={filters.maxMileage} onChange={onFilterChange} placeholder="Max Mileage (km)" />
        </div>
      </div>

      {!loading && vehicles.length === 0 ? (
        <div className="card cardPad" style={{ textAlign: "center", padding: "56px 24px", color: "var(--text-muted)" }}>
          No vehicles found for this filter.
        </div>
      ) : (
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(320px, 1fr))", gap: "18px" }}>
          {vehicles.map((vehicle) => {
            const cover = getImageUrl(vehicle?.images?.[0]?.url);
            const statusMeta = getVehicleStatusMeta(vehicle.status);

            return (
              <div key={vehicle._id} className="card" style={{ overflow: "hidden", display: "grid" }}>
                <button
                  type="button"
                  onClick={() => navigate(`/vehicles/${vehicle._id}`)}
                  style={{ border: "none", background: "transparent", padding: 0, cursor: "pointer", textAlign: "left" }}
                >
                  <div style={{ position: "relative", aspectRatio: "4 / 3", background: "rgba(12,58,87,0.08)" }}>
                    {cover ? (
                      <img src={cover} alt={vehicle.brand} style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }} />
                    ) : (
                      <div style={{ width: "100%", height: "100%", display: "grid", placeItems: "center", color: "var(--text-muted)", fontWeight: 600 }}>
                        No Photo Available
                      </div>
                    )}

                    <div style={{ position: "absolute", top: "14px", right: "14px" }}>
                      <span className={statusMeta.badge}>{statusMeta.label}</span>
                    </div>
                  </div>
                </button>

                <div className="cardPad" style={{ display: "grid", gap: "16px" }}>
                  <div style={{ display: "grid", gap: "4px" }}>
                    <div style={{ fontSize: "22px", fontWeight: 800, letterSpacing: "-0.03em", color: "var(--text)" }}>
                      {vehicle.brand}
                    </div>
                    <div className="sub">{vehicle.type || "Type"} • {vehicle.year || "Year not set"}</div>
                  </div>

                  <div style={{ fontSize: "22px", fontWeight: 800, color: "var(--primary)" }}>{formatCurrency(vehicle.price)}</div>

                  <div style={{ display: "grid", gap: "10px" }}>
                    <DetailRow label="Registration" value={vehicle.vehicleNumber || "Not added"} />
                    <DetailRow label="Fuel" value={vehicle.fuelType || "Not specified"} />
                    <DetailRow label="Transmission" value={vehicle.transmission || "Not specified"} />
                    <DetailRow label="Mileage" value={vehicle.mileage ? `${Number(vehicle.mileage).toLocaleString()} km` : "Not specified"} />
                    <DetailRow label="Condition" value={vehicle.status ? statusMeta.label : "Unknown"} />
                    <DetailRow
                      label="Notes"
                      value={vehicle.details ? `${vehicle.details.slice(0, 56)}${vehicle.details.length > 56 ? "..." : ""}` : "No details added"}
                    />
                  </div>

                  <div style={{ display: "flex", gap: "10px", flexWrap: "wrap" }}>
                    <button
                      type="button"
                      className="btn btnPrimary"
                      onClick={() => bookNow(vehicle._id, vehicle.status)}
                      disabled={vehicle.status !== "available"}
                      style={{ flex: 1 }}
                    >
                      Book Now
                    </button>

                    {canManageVehicles && (
                      <button type="button" className="btn" onClick={() => navigate(`/vehicles/edit/${vehicle._id}`)} style={{ flex: 1 }}>
                        Edit
                      </button>
                    )}

                    {canManageVehicles && (
                      <button type="button" className="btn btnDanger" onClick={() => onDelete(vehicle._id)}>
                        Delete
                      </button>
                    )}
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
